import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';

const OIDC_CONFIG = {
  authorizationEndpoint: 'https://your-oidc-provider.com/oauth2/authorize',
  tokenEndpoint: 'https://your-oidc-provider.com/oauth2/token',
  clientId: 'your-client-id',
  redirectUri: window.location.origin + '/callback',
  scope: 'openid profile email'
};

function generateCodeVerifier() {
  const array = new Uint8Array(32);
  crypto.getRandomValues(array);
  return base64URLEncode(array);
}

function base64URLEncode(buffer) {
  const base64 = btoa(String.fromCharCode(...new Uint8Array(buffer)));
  return base64.replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
}

async function sha256(plain) {
  const encoder = new TextEncoder();
  const data = encoder.encode(plain);
  return await crypto.subtle.digest('SHA-256', data);
}

async function generateCodeChallenge(verifier) {
  const hashed = await sha256(verifier);
  return base64URLEncode(hashed);
}

function parseJwt(token) {
  const base64Url = token.split('.')[1];
  const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
  const jsonPayload = decodeURIComponent(atob(base64).split('').map(function(c) {
    return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
  }).join(''));
  return JSON.parse(jsonPayload);
}

function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const storedTokens = localStorage.getItem('oidc_tokens');
    if (storedTokens) {
      const tokens = JSON.parse(storedTokens);
      const userProfile = parseJwt(tokens.id_token);
      setUser(userProfile);
    }
    setLoading(false);
  }, []);

  const login = async () => {
    const codeVerifier = generateCodeVerifier();
    const codeChallenge = await generateCodeChallenge(codeVerifier);
    
    sessionStorage.setItem('code_verifier', codeVerifier);

    const params = new URLSearchParams({
      response_type: 'code',
      client_id: OIDC_CONFIG.clientId,
      redirect_uri: OIDC_CONFIG.redirectUri,
      scope: OIDC_CONFIG.scope,
      code_challenge: codeChallenge,
      code_challenge_method: 'S256'
    });

    window.location.href = `${OIDC_CONFIG.authorizationEndpoint}?${params.toString()}`;
  };

  const logout = () => {
    localStorage.removeItem('oidc_tokens');
    setUser(null);
  };

  const handleCallback = async (code) => {
    const codeVerifier = sessionStorage.getItem('code_verifier');
    sessionStorage.removeItem('code_verifier');

    const params = new URLSearchParams({
      grant_type: 'authorization_code',
      code: code,
      redirect_uri: OIDC_CONFIG.redirectUri,
      client_id: OIDC_CONFIG.clientId,
      code_verifier: codeVerifier
    });

    try {
      const response = await fetch(OIDC_CONFIG.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        },
        body: params.toString()
      });

      if (!response.ok) {
        throw new Error('Token exchange failed');
      }

      const tokens = await response.json();
      localStorage.setItem('oidc_tokens', JSON.stringify(tokens));

      const userProfile = parseJwt(tokens.id_token);
      setUser(userProfile);

      window.history.replaceState({}, document.title, '/');
    } catch (error) {
      console.error('Error exchanging code for tokens:', error);
    }
  };

  return (
    <AuthContext.Provider value={{ user, login, logout, handleCallback, loading }}>
      {children}
    </AuthContext.Provider>
  );
}

const AuthContext = React.createContext();

function useAuth() {
  return React.useContext(AuthContext);
}

function CallbackHandler() {
  const { handleCallback } = useAuth();
  const [processed, setProcessed] = useState(false);

  useEffect(() => {
    if (!processed) {
      const params = new URLSearchParams(window.location.search);
      const code = params.get('code');
      
      if (code) {
        handleCallback(code);
        setProcessed(true);
      }
    }
  }, [handleCallback, processed]);

  return (
    <div style={{ padding: '20px', textAlign: 'center' }}>
      <h2>Processing authentication...</h2>
    </div>
  );
}

function HomePage() {
  const { user, login, logout } = useAuth();

  return (
    <div style={{ padding: '20px', maxWidth: '800px', margin: '0 auto' }}>
      <h1>OpenID Connect SPA</h1>
      
      {user ? (
        <div>
          <h2>Welcome, {user.name || user.email || user.sub}!</h2>
          <div style={{ background: '#f5f5f5', padding: '15px', borderRadius: '5px', marginTop: '20px' }}>
            <h3>User Profile</h3>
            <pre style={{ textAlign: 'left', overflow: 'auto' }}>
              {JSON.stringify(user, null, 2)}
            </pre>
          </div>
          <button 
            onClick={logout}
            style={{
              marginTop: '20px',
              padding: '10px 20px',
              fontSize: '16px',
              cursor: 'pointer',
              background: '#dc3545',
              color: 'white',
              border: 'none',
              borderRadius: '5px'
            }}
          >
            Logout
          </button>
        </div>
      ) : (
        <div>
          <p>You are not logged in.</p>
          <button 
            onClick={login}
            style={{
              marginTop: '20px',
              padding: '10px 20px',
              fontSize: '16px',
              cursor: 'pointer',
              background: '#007bff',
              color: 'white',
              border: 'none',
              borderRadius: '5px'
            }}
          >
            Login with OpenID Connect
          </button>
        </div>
      )}
    </div>
  );
}

function App() {
  const { loading } = useAuth();
  const isCallback = window.location.pathname === '/callback' || window.location.search.includes('code=');

  if (loading) {
    return <div style={{ padding: '20px', textAlign: 'center' }}>Loading...</div>;
  }

  if (isCallback) {
    return <CallbackHandler />;
  }

  return <HomePage />;
}

function Root() {
  return (
    <AuthProvider>
      <App />
    </AuthProvider>
  );
}

const container = document.getElementById('root');
const root = createRoot(container);
root.render(<Root />);